class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) {
        this->characters = characters;
        this->combinationLength = combinationLength;
        this->index = 0;
        this->result = "";
    }

    string next() {
        if (index >= characters.size() - combinationLength + 1) {
            return "";
        }
        result = characters.substr(index, combinationLength);
        index += combinationLength;
        return result;
    }

    bool hasNext() {
        return index + combinationLength <= characters.size();
    }

private:
    string characters;
    int combinationLength;
    int index;
    string result;
};
```
